import React from 'react';
import './ButtonsHolder.css';

const ButtonsHolder = () => {
  return (
    <div className='buttons'>
          <button className='aboutme' onClick={() => { scrollTo('FirstSection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['About Me']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>
          <button className='skills' onClick={() => { scrollTo('secondsection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['My Skills']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>
          <button className='projects' onClick={() => { scrollTo('thirdsection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['My Portfolio']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1500} />
            <span className='red-cursor'>|</span>
          </button>
          <button className='contact' onClick={() => { scroll.scrollToBottom() }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['Contact Me']}
              loop={1}
              typeSpeed={135}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>
        </div>
)};

export default ButtonsHolder;
